use serde::{Deserialize, Serialize};
use std::io::{self, Read};

mod realcompare_ref {
    pub const LT: &str = "LT";
    pub const EQ: &str = "EQ";
    pub const GT: &str = "GT";

    pub fn realcompare(a: f64, b: f64) -> &'static str {
        let scale = a.abs().max(b.abs());
        if scale == 0.0 {
            return "EQ";
        }
        let eps = 0.5e-5 * scale;
        let diff = a - b;
        if diff > eps {
            "GT"
        } else if diff < -eps {
            "LT"
        } else {
            "EQ"
        }
    }
}

use realcompare_ref::*;

#[derive(Deserialize)]
struct Parameters {
    LENGTH1: f64,
    RADIUS1: f64,
    EPSILON: f64,
    AREA1: f64,
    Q_PTS: usize,
    QUADS: usize,
    DIST: f64,
    N_PTS: usize,
    K_PTS: usize,
    A_PTS: usize,
    B_PTS: usize,
    C_PTS: usize,
    D_PTS: usize,
    E_PTS: usize,
    F_PTS: usize,
    G_PTS: usize,
    LENGTH2: f64,
    RADIUS2: f64,
    AREA2: f64,
}

#[derive(Deserialize)]
struct Input {
    numpoints: usize,
    x: Vec<f64>,
    y: Vec<f64>,
    parameters: Parameters,
    lcm: Vec<Vec<String>>,
    pum_diag: Vec<bool>,
}

#[derive(Serialize)]
struct Output {
    cmv: Vec<bool>,
    pum: Vec<Vec<bool>>,
    fuv: Vec<bool>,
    launch: bool,
}

fn compare(a: f64, b: f64) -> std::cmp::Ordering {
    match realcompare(a, b) {
        "GT" => std::cmp::Ordering::Greater,
        "LT" => std::cmp::Ordering::Less,
        _ => std::cmp::Ordering::Equal,
    }
}

fn dist(x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    ((x1 - x2).powi(2) + (y1 - y2).powi(2)).sqrt()
}

fn get_quadrant(x: f64, y: f64) -> usize {
    if x >= 0.0 && y >= 0.0 { 1 }
    else if x < 0.0 && y >= 0.0 { 2 }
    else if x < 0.0 && y < 0.0 { 3 }
    else { 4 } // x >= 0.0 && y < 0.0
}

// Note: The quadrant rules in spec: (0,0) I, (-1,0) II, (0,-1) III, (0,1) I, (1,0) I.
// Priority: I, II, III, IV.
// x=0, y=0 -> I (matches)
// x=-1, y=0 -> II (matches)
// x=0, y=-1 -> III (matches)
// x=0, y=1 -> I (matches)
// x=1, y=0 -> I (matches)
// My get_quadrant:
// (0,0) -> 1 (I) - OK
// (-1,0) -> 2 (II) - OK
// (0,-1) -> 3 (III) - OK
// (0,1) -> 1 (I) - OK
// (1,0) -> 1 (I) - OK
// Wait, x >= 0 and y >= 0 is I.
// If x < 0 and y >= 0 is II.
// If x < 0 and y < 0 is III.
// If x >= 0 and y < 0 is IV.
// Let's re-verify:
// (0,0): x=0, y=0 -> I. OK.
// (-1,0): x=-1, y=0 -> II. OK.
// (0,-1): x=0, y=-1 -> III. Wait, 0 >= 0 and -1 < 0 -> IV.
// Spec says: "the point (0,-1) is in quadrant III".
// "the point (0,1) is in quadrant I".
// "the point (1,0) is in quadrant I".
// Let's re-read: "priority of decision will be by quadrant number, i.e., I, II, III, IV."
// This implies if a point is on a boundary, it goes to the lowest numbered quadrant it belongs to.
// Quadrants:
// I: x >= 0, y >= 0
// II: x < 0, y >= 0 (Wait, if x=0, y=1 it's I)
// III: x <= 0, y < 0 (Wait, if x=0, y=-1 it's III)
// IV: x > 0, y < 0
// Let's try this:
// Point (x,y)
// If x >= 0 and y >= 0 -> I
// Else if x < 0 and y >= 0 -> II
// Else if x <= 0 and y < 0 -> III
// Else -> IV (x > 0 and y < 0)
// Test:
// (0,0): x=0, y=0 -> I. OK.
// (-1,0): x=-1, y=0 -> II. OK.
// (0,-1): x=0, y=-1 -> x<=0 && y<0 is true. III. OK.
// (0,1): x=0, y=1 -> I. OK.
// (1,0): x=1, y=0 -> I. OK.
// This logic works.

fn get_quadrant_fixed(x: f64, y: f64) -> usize {
    if x >= 0.0 && y >= 0.0 { 1 }
    else if x < 0.0 && y >= 0.0 { 2 }
    else if x <= 0.0 && y < 0.0 { 3 }
    else { 4 }
}

fn get_triangle_area(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    0.5 * (x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)).abs()
}

fn get_min_circle_radius(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    let a = dist(x1, y1, x2, y2);
    let b = dist(x2, y2, x3, y3);
    let c = dist(x3, y3, x1, y1);

    // Check if obtuse or right triangle
    if a*a + b*b <= c*c { return c / 2.0; }
    if a*a + c*c <= b*b { return b / 2.0; }
    if b*b + c*c <= a*a { return a / 2.0; }

    // Acute triangle: circumradius
    let area = get_triangle_area(x1, y1, x2, y2, x3, y3);
    if area == 0.0 {
        return (a.max(b).max(c)) / 2.0;
    }
    (a * b * c) / (4.0 * area)
}

fn get_angle(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> Option<f64> {
    // Vertex is (x2, y2)
    let v1x = x1 - x2;
    let v1y = y1 - y2;
    let v2x = x3 - x2;
    let v2y = y3 - y2;

    let d1 = (v1x*v1x + v1y*v1y).sqrt();
    let d2 = (v2x*v2x + v2y*v2y).sqrt();

    if d1 == 0.0 || d2 == 0.0 {
        return None;
    }

    let dot = v1x*v2x + v1y*v2y;
    let cos_theta = (dot / (d1 * d2)).clamp(-1.0, 1.0);
    Some(cos_theta.acos())
}

fn main() {
    let mut buffer = String::new();
    io::stdin().read_to_string(&mut buffer).unwrap();
    let input: Input = serde_json::from_str(&buffer).unwrap();

    let n = input.numpoints;
    let x = &input.x;
    let y = &input.y;
    let p = &input.parameters;

    let mut cmv = vec![false; 15];

    // LIC 1
    for i in 0..n-1 {
        if compare(dist(x[i], y[i], x[i+1], y[i+1]), p.LENGTH1) == std::cmp::Ordering::Greater {
            cmv[0] = true;
            break;
        }
    }

    // LIC 2
    for i in 0..n-2 {
        if compare(get_min_circle_radius(x[i], y[i], x[i+1], y[i+1], x[i+2], y[i+2]), p.RADIUS1) == std::cmp::Ordering::Greater {
            cmv[1] = true;
            break;
        }
    }

    // LIC 3
    for i in 0..n-2 {
        if let Some(angle) = get_angle(x[i], y[i], x[i+1], y[i+1], x[i+2], y[i+2]) {
            if compare(angle, std::f64::consts::PI - p.EPSILON) == std::cmp::Ordering::Less || 
               compare(angle, std::f64::consts::PI + p.EPSILON) == std::cmp::Ordering::Greater {
                cmv[2] = true;
                break;
            }
        }
    }

    // LIC 4
    for i in 0..n-2 {
        if compare(get_triangle_area(x[i], y[i], x[i+1], y[i+1], x[i+2], y[i+2]), p.AREA1) == std::cmp::Ordering::Greater {
            cmv[3] = true;
            break;
        }
    }

    // LIC 5
    for i in 0..=n - p.Q_PTS {
        let mut quads = std::collections::HashSet::new();
        for j in i..i + p.Q_PTS {
            quads.insert(get_quadrant_fixed(x[j], y[j]));
        }
        if quads.len() > p.QUADS {
            cmv[4] = true;
            break;
        }
    }

    // LIC 6
    for i in 0..n-1 {
        if compare(x[i+1] - x[i], 0.0) == std::cmp::Ordering::Less {
            cmv[5] = true;
            break;
        }
    }

    // LIC 7
    if n >= 3 {
        for i in 0..=n - p.N_PTS {
            let x1 = x[i];
            let y1 = y[i];
            let xn = x[i + p.N_PTS - 1];
            let yn = y[i + p.N_PTS - 1];

            let mut met = false;
            if x1 == xn && y1 == yn {
                for j in i + 1..i + p.N_PTS - 1 {
                    if compare(dist(x[j], y[j], x1, y1), p.DIST) == std::cmp::Ordering::Greater {
                        met = true;
                        break;
                    }
                }
            } else {
                for j in i..i + p.N_PTS {
                    let num = ((yn - y1) * x[j] - (xn - x1) * y[j] + xn * y1 - yn * x1).abs();
                    let den = dist(x1, y1, xn, yn);
                    if compare(num / den, p.DIST) == std::cmp::Ordering::Greater {
                        met = true;
                        break;
                    }
                }
            }
            if met {
                cmv[6] = true;
                break;
            }
        }
    }

    // LIC 8
    if n >= 3 {
        for i in 0..n - p.K_PTS - 1 {
            if compare(dist(x[i], y[i], x[i + p.K_PTS + 1], y[i + p.K_PTS + 1]), p.LENGTH1) == std::cmp::Ordering::Greater {
                cmv[7] = true;
                break;
            }
        }
    }

    // LIC 9
    if n >= 5 {
        for i in 0..n - (p.A_PTS + p.B_PTS + 2) {
            let p1 = (x[i], y[i]);
            let p2 = (x[i + p.A_PTS + 1], y[i + p.A_PTS + 1]);
            let p3 = (x[i + p.A_PTS + p.B_PTS + 2], y[i + p.A_PTS + p.B_PTS + 2]);
            if compare(get_min_circle_radius(p1.0, p1.1, p2.0, p2.1, p3.0, p3.1), p.RADIUS1) == std::cmp::Ordering::Greater {
                cmv[8] = true;
                break;
            }
        }
    }

    // LIC 10
    if n >= 5 {
        for i in 0..n - (p.C_PTS + p.D_PTS + 2) {
            let p1 = (x[i], y[i]);
            let p2 = (x[i + p.C_PTS + 1], y[i + p.C_PTS + 1]);
            let p3 = (x[i + p.C_PTS + p.D_PTS + 2], y[i + p.C_PTS + p.D_PTS + 2]);
            if let Some(angle) = get_angle(p1.0, p1.1, p2.0, p2.1, p3.0, p3.1) {
                if compare(angle, std::f64::consts::PI - p.EPSILON) == std::cmp::Ordering::Less || 
                   compare(angle, std::f64::consts::PI + p.EPSILON) == std::cmp::Ordering::Greater {
                    cmv[9] = true;
                    break;
                }
            }
        }
    }

    // LIC 11
    if n >= 5 {
        for i in 0..n - (p.E_PTS + p.F_PTS + 2) {
            let p1 = (x[i], y[i]);
            let p2 = (x[i + p.E_PTS + 1], y[i + p.E_PTS + 1]);
            let p3 = (x[i + p.E_PTS + p.F_PTS + 2], y[i + p.E_PTS + p.F_PTS + 2]);
            if compare(get_triangle_area(p1.0, p1.1, p2.0, p2.1, p3.0, p3.1), p.AREA1) == std::cmp::Ordering::Greater {
                cmv[10] = true;
                break;
            }
        }
    }

    // LIC 12
    if n >= 3 {
        for i in 0..n {
            for j in i + p.G_PTS + 1..n {
                if compare(x[j] - x[i], 0.0) == std::cmp::Ordering::Less {
                    cmv[11] = true;
                    break;
                }
            }
            if cmv[11] { break; }
        }
    }

    // LIC 13
    if n >= 3 {
        let mut part1 = false;
        let mut part2 = false;
        for i in 0..n - p.K_PTS - 1 {
            let d = dist(x[i], y[i], x[i + p.K_PTS + 1], y[i + p.K_PTS + 1]);
            if compare(d, p.LENGTH1) == std::cmp::Ordering::Greater { part1 = true; }
            if compare(d, p.LENGTH2) == std::cmp::Ordering::Less { part2 = true; }
        }
        cmv[12] = part1 && part2;
    }

    // LIC 14
    if n >= 5 {
        let mut part1 = false;
        let mut part2 = false;
        for i in 0..n - (p.A_PTS + p.B_PTS + 2) {
            let p1 = (x[i], y[i]);
            let p2 = (x[i + p.A_PTS + 1], y[i + p.A_PTS + 1]);
            let p3 = (x[i + p.A_PTS + p.B_PTS + 2], y[i + p.A_PTS + p.B_PTS + 2]);
            let r = get_min_circle_radius(p1.0, p1.1, p2.0, p2.1, p3.0, p3.1);
            if compare(r, p.RADIUS1) == std::cmp::Ordering::Greater { part1 = true; }
            if compare(r, p.RADIUS2) == std::cmp::Ordering::Less { part2 = true; }
        }
        cmv[13] = part1 && part2;
    }

    // LIC 15
    if n >= 5 {
        let mut part1 = false;
        let mut part2 = false;
        for i in 0..n - (p.E_PTS + p.F_PTS + 2) {
            let p1 = (x[i], y[i]);
            let p2 = (x[i + p.E_PTS + 1], y[i + p.E_PTS + 1]);
            let p3 = (x[i + p.E_PTS + p.F_PTS + 2], y[i + p.E_PTS + p.F_PTS + 2]);
            let area = get_triangle_area(p1.0, p1.1, p2.0, p2.1, p3.0, p3.1);
            if compare(area, p.AREA1) == std::cmp::Ordering::Greater { part1 = true; }
            if compare(area, p.AREA2) == std::cmp::Ordering::Less { part2 = true; }
        }
        cmv[14] = part1 && part2;
    }

    // PUM
    let mut pum = vec![vec![true; 15]; 15];
    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                pum[i][j] = input.pum_diag[i];
            } else {
                let conn = &input.lcm[i][j];
                if conn == "NOTUSED" {
                    pum[i][j] = true;
                } else if conn == "ANDD" {
                    pum[i][j] = cmv[i] && cmv[j];
                } else if conn == "ORR" {
                    pum[i][j] = cmv[i] || cmv[j];
                }
            }
        }
    }

    // FUV
    let mut fuv = vec![false; 15];
    for i in 0..15 {
        if !pum[i][i] {
            fuv[i] = true;
        } else {
            let mut all_true = true;
            for j in 0..15 {
                if !pum[i][j] {
                    all_true = false;
                    break;
                }
            }
            fuv[i] = all_true;
        }
    }

    // LAUNCH
    let mut launch = true;
    for i in 0..15 {
        if !fuv[i] {
            launch = false;
            break;
        }
    }

    let output = Output { cmv, pum, fuv, launch };
    println!("{}", serde_json::to_string(&output).unwrap());
}
